import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{r as a,o as r,c,f as d,b as e,e as o,a as s,i}from"./app-d6a6dcfa.js";const l={},h=e("p",null,[o("Тема поддерживает функцию блога с "),e("code",null,"vuepress-plugin-blog2"),o(" по умолчанию, и по умолчанию она "),e("strong",null,"отключена"),o(".")],-1),p=e("p",null,[o("Если вам нужна функциональность блога, вы можете установить "),e("code",null,"plugins.blog: true"),o(" в параметрах темы, чтобы включить функциональность блога.")],-1),u=e("h2",{id:"введение",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#введение","aria-hidden":"true"},"#"),o(" Введение")],-1),_=e("p",null,"После включения функции блога тема позволяет настраивать категории, теги, будь то статья, появляется ли она на временной шкале, звездочки, липкие и другие функции через переднюю часть страницы.",-1),m={class:"hint-container tip"},f=e("p",{class:"hint-container-title"},"Демо",-1),b={href:"https://mister-hope.com/en/",target:"_blank",rel:"noopener noreferrer"},v=e("code",null,"vuepress-theme-hope",-1),x=i('<h2 id="поддержка-i18n" tabindex="-1"><a class="header-anchor" href="#поддержка-i18n" aria-hidden="true">#</a> Поддержка I18n</h2><p>Тема добавляет поддержку i18n в систему блогов. Вы можете установить разные настройки блога для каждого языка, используя <code>locales</code> в настройках темы.</p><p>Если у вас несколько языков, список статей, временная шкала и т. д. для каждого языка останутся независимыми.</p><h2 id="боковая-панель" tabindex="-1"><a class="header-anchor" href="#боковая-панель" aria-hidden="true">#</a> Боковая панель</h2><p>Тема предоставляет боковую панель с информацией о блоге. Боковая панель будет отображаться на странице, связанной с блогом (она будет отображаться справа на рабочем столе и убираться в боковую панель в мобильном представлении).</p><p>Вы можете управлять поведением отображения боковой панели на страницах, не связанных с блогом, с помощью <code>blog.sidebarDisplay</code> в параметрах темы. Необязательные значения: <code>&quot;mobile&quot; | &quot;none&quot; | &quot;always&quot;</code>. По умолчанию используется <code>&quot;mobile&quot;</code>, то есть когда вы посещаете страницы, не связанные с блогом, в мобильном представлении, вы также можете увидеть его на боковой панели.</p><h2 id="пагинация" tabindex="-1"><a class="header-anchor" href="#пагинация" aria-hidden="true">#</a> Пагинация</h2><p>Для списка статей на всех страницах мы отобразим компонент пагинации внизу. Вы можете использовать этот компонент для быстрого перехода к первой странице, последней странице и двум страницам до и после. Вы также можете ввести номер для перехода на указанную страницу.</p><p>Количество статей на странице по умолчанию равно <code>10</code>, вы можете установить <code>blog.articlePerPage</code> в параметрах темы, чтобы переопределить это значение.</p><h2 id="ограничение" tabindex="-1"><a class="header-anchor" href="#ограничение" aria-hidden="true">#</a> Ограничение</h2><div class="hint-container warning"><p class="hint-container-title">Горячее обновление отключено по умолчанию</p><p>Из соображений производительности горячие обновления не включены для данных, связанных с блогами, по умолчанию в devServer, т. е. если вы добавляете новые статьи или изменяете категории, время, теги, прикрепляемые, звездочки и т. д. существующих статей, связанные данные всего сайта не будет обновляться, пока вы не перезапустите сервер разработки.</p><p>Кроме того, поскольку информация блога будет записана в базовые данные VuePress, изменение этого файла приведет к перезапуску приложения, поэтому время чтения (включая информацию о количестве слов), которое чувствительно к содержимому Markdown, не будет действовать в devServer.</p><p>Если вы хотите, чтобы они вступили в силу или обновлялись в режиме реального времени, вам нужно установить <code>hotReload: true</code> и принять тот факт, что каждое изменение будет вызывать обновление страницы и некоторое время с белым экраном из-за интенсивной работы по пересчету.</p></div>',11);function g(q,k){const t=a("ExternalLinkIcon");return r(),c("div",null,[h,p,d(" more "),u,_,e("div",m,[f,e("p",null,[e("a",b,[o("Вот демонстрация"),s(t)]),o(" для предварительного просмотра блогов, созданных с помощью "),v,o(".")])]),x])}const w=n(l,[["render",g],["__file","intro.html.vue"]]);export{w as default};
